mapper.select:
/* AccountingDlvrMapper.getAccountingDlvrDayExcelList */ SELECT TO_CHAR(TO_DATE(A.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , A.STORE_CD , B.STORE_NM , DECODE(A.DLVR_IN_FG, 0 ,'일반', C.NMCODE_NM) AS DLVR_NM , NVL(A.REAL_SALE_AMT, 0) - NVL(A.DLVR_AMT, 0) AS REAL_SALE_AMT_EXCEPT_DLVR , NVL(A.REAL_SALE_AMT, 0) - NVL(A.VAT_AMT, 0) - NVL(A.DLVR_AMT, 0) - NVL(A.DLVR_VAT_AMT, 0) AS GA_AMT_EXCEPT_DLVR , NVL(A.VAT_AMT, 0) - NVL(A.DLVR_VAT_AMT,0) AS VAT_AMT_EXCEPT_DLVR , NVL(A.REAL_SALE_AMT, 0) AS REAL_SALE_AMT , NVL(A.REAL_SALE_AMT, 0) - NVL(A.VAT_AMT, 0) AS GA_AMT , NVL(A.VAT_AMT, 0) AS VAT_AMT , NVL(A.DLVR_AMT , 0) AS DLVR_AMT FROM TB_SL_DAILY_TOTAL_ORDAPP A , TB_MS_STORE B , TB_CM_NMCODE C WHERE A.HQ_OFFICE_CD = #{hqOfficeCd} AND A.SALE_DATE BETWEEN #{startDate} AND #{endDate} AND B.STORE_CD = A.STORE_CD AND C.NMCODE_GRP_CD (+) = '112' AND C.NMCODE_CD (+) = A.DLVR_IN_FG
AND A.STORE_CD IN (${storeCdQuery})
ORDER BY A.SALE_DATE , A.STORE_CD , A.DLVR_IN_FG

/* AccountingDlvrMapper.getAccountingDlvrMonthExcelList */ SELECT TO_CHAR(TO_DATE(A.SALE_YM, 'yyyymm'), 'yyyy-mm') AS SALE_YM , A.STORE_CD , B.STORE_NM , DECODE(A.DLVR_IN_FG, 0 ,'일반', C.NMCODE_NM) AS DLVR_NM , NVL(A.REAL_SALE_AMT, 0) - NVL(A.DLVR_AMT, 0) AS REAL_SALE_AMT_EXCEPT_DLVR , NVL(A.REAL_SALE_AMT, 0) - NVL(A.VAT_AMT, 0) - NVL(A.DLVR_AMT, 0) - NVL(A.DLVR_VAT_AMT, 0) AS GA_AMT_EXCEPT_DLVR , NVL(A.VAT_AMT, 0) - NVL(A.DLVR_VAT_AMT,0) AS VAT_AMT_EXCEPT_DLVR , NVL(A.REAL_SALE_AMT, 0) AS REAL_SALE_AMT , NVL(A.REAL_SALE_AMT, 0) - NVL(A.VAT_AMT, 0) AS GA_AMT , NVL(A.VAT_AMT, 0) AS VAT_AMT , NVL(A.DLVR_AMT , 0) AS DLVR_AMT FROM TB_SL_MONTHLY_TOTAL_ORDAPP A , TB_MS_STORE B , TB_CM_NMCODE C WHERE A.HQ_OFFICE_CD = #{hqOfficeCd} AND A.SALE_YM BETWEEN #{startMonth} AND #{endMonth} AND B.STORE_CD = A.STORE_CD AND C.NMCODE_GRP_CD (+) = '112' AND C.NMCODE_CD (+) = A.DLVR_IN_FG
AND A.STORE_CD IN (${storeCdQuery})
ORDER BY A.SALE_YM , A.STORE_CD , A.DLVR_IN_FG
